#include <bits/stdc++.h>
using namespace std;

const int N=3e5+10;

int n,p[N],f[N][2],c[2][N];
char s[N];

int ask(int x,int c[]){
    int res=-1;
    for(;x;x-=(x&(-x)))
        res=max(res,c[x]);
    return res;
}

void add(int x,int k,int c[]){
    for(;x<=n;x+=(x&(-x)))
        c[x]=max(c[x],k);
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&p[i]);
    scanf("%s",s+1);
    memset(c,-1,sizeof(c));
    int ans=0;
    for(int i=1;i<=n;i++){
        f[i][0]=ask(p[i],c[0])+1;
        f[i][1]=ask(n-p[i]+1,c[1])+1;
        int num=max(f[i][0],f[i][1]);
        if(s[num+1]=='U')
            add(p[i],num,c[0]);
        if(s[num+1]=='D')
            add(n-p[i]+1,num,c[1]);
        ans=max(ans,num);
    }
    printf("%d",ans);
    return 0;
}
